def solve(n: int) -> int:
    comma_count = 0
    for i in range(1, n + 1):
        num_str = str(i)
        # Count commas by checking every third digit from the right
        # Start from the end of the string and move left, checking every third digit
        # We can use a loop with a step of -3 to check every third digit
        for j in range(len(num_str) - 1, -1, -3):
            if j > 0 and j % 3 == 0:
                comma_count += 1
    return comma_count
